#include <ESP8266WiFi.h>

const int LED = D4;  // Built-in LED
const int SLEEP_TIME = 60;  // Sleep for 60 seconds

void setup() {
  Serial.begin(115200);
  pinMode(LED, OUTPUT);

  Serial.println("Waking up...");

  // Blink LED
  for (int i = 0; i < 3; i++) {
    digitalWrite(LED, LOW);  // LED is active LOW
    delay(100);
    digitalWrite(LED, HIGH);
    delay(100);
  }

  // Read sensor data here
  int sensorValue = analogRead(A0);
  Serial.print("Sensor reading: ");
  Serial.println(sensorValue);

  // Go to deep sleep
  Serial.print("Going to sleep for ");
  Serial.print(SLEEP_TIME);
  Serial.println(" seconds...");

  ESP.deepSleep(SLEEP_TIME * 1000000);  // Microseconds
}

void loop() {
  // Never executed - device resets after deep sleep
}

