#include <ESP8266WiFi.h>

// Read battery voltage
float getBatteryVoltage() {
  // Read ADC (0-1024)
  int rawValue = analogRead(A0);

  // Convert to voltage (ESP8266 ADC is 0-1V, with voltage divider)
  // Feather HUZZAH has internal voltage divider
  float voltage = (rawValue / 1024.0) * 4.2;  // Max LiPo voltage

  return voltage;
}

void setup() {
  Serial.begin(115200);
  pinMode(A0, INPUT);

  Serial.println("Adafruit Feather HUZZAH ESP8266");
}

void loop() {
  float vbat = getBatteryVoltage();

  Serial.print("Battery Voltage: ");
  Serial.print(vbat);
  Serial.println("V");

  // Calculate percentage (rough estimate)
  float percentage = ((vbat - 3.3) / (4.2 - 3.3)) * 100.0;
  percentage = constrain(percentage, 0, 100);

  Serial.print("Battery Level: ");
  Serial.print(percentage);
  Serial.println("%");

  delay(5000);
}

