#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "esp_log.h"

static const char *TAG = "ESP32-P4";

// Task for Core 0
void core0_task(void *pvParameters) {
    while(1) {
        ESP_LOGI(TAG, "Core 0 processing at 400MHz");
        vTaskDelay(pdMS_TO_TICKS(1000));
    }
}

// Task for Core 1
void core1_task(void *pvParameters) {
    while(1) {
        ESP_LOGI(TAG, "Core 1 processing at 400MHz");
        vTaskDelay(pdMS_TO_TICKS(1000));
    }
}

void app_main(void) {
    ESP_LOGI(TAG, "ESP32-P4 Dual-Core Demo");

    // Create task on Core 0
    xTaskCreatePinnedToCore(core0_task, "Core0", 4096, NULL, 5, NULL, 0);

    // Create task on Core 1
    xTaskCreatePinnedToCore(core1_task, "Core1", 4096, NULL, 5, NULL, 1);
}

